import React, { useState, useRef } from "react";

export default function Profile() {
  const storedUser = JSON.parse(localStorage.getItem("user") || "{}");
  const fileRef = useRef(null);
  const [photo, setPhoto] = useState(localStorage.getItem("profile_photo") || null);
  const [profile, setProfile] = useState({
    name: storedUser.name || "", email: storedUser.email || "",
    phone: storedUser.phone || "", role: storedUser.role || "",
    bio: storedUser.bio || "", skills: storedUser.skills || "",
  });
  const [saving, setSaving] = useState(false);
  const [success, setSuccess] = useState("");

  const handleChange = (e) => setProfile({...profile,[e.target.name]:e.target.value});

  const handlePhoto = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 2*1024*1024) { alert("Max 2MB"); return; }
    const reader = new FileReader();
    reader.onloadend = () => { setPhoto(reader.result); localStorage.setItem("profile_photo", reader.result); };
    reader.readAsDataURL(file);
  };

  const save = () => {
    setSaving(true);
    localStorage.setItem("user", JSON.stringify({...storedUser,...profile}));
    setTimeout(()=>{setSaving(false);setSuccess("Saved!");setTimeout(()=>setSuccess(""),3000);},600);
  };

  const S = {
    page: { background:"#0f172a", minHeight:"100vh", padding:"32px", fontFamily:"'Segoe UI',sans-serif" },
    title: { fontSize:"24px", fontWeight:"700", color:"#f1f5f9", marginBottom:"4px" },
    sub: { fontSize:"13px", color:"#64748b", marginBottom:"28px" },
    card: { background:"#1e293b", border:"1px solid #334155", borderRadius:"16px", padding:"28px", maxWidth:"660px" },
    photoRow: { display:"flex", alignItems:"center", gap:"20px", marginBottom:"28px", paddingBottom:"24px", borderBottom:"1px solid #334155" },
    avatar: { width:"72px", height:"72px", borderRadius:"50%", objectFit:"cover", border:"2px solid #2dd4bf" },
    avatarPlaceholder: { width:"72px", height:"72px", borderRadius:"50%", background:"linear-gradient(135deg,#0d9488,#0891b2)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:"26px", fontWeight:"800", color:"white", border:"2px solid #2dd4bf", flexShrink:0 },
    name: { fontSize:"18px", fontWeight:"700", color:"#f1f5f9" },
    email: { fontSize:"13px", color:"#64748b", marginTop:"2px" },
    roleBadge: { display:"inline-block", marginTop:"6px", padding:"3px 10px", borderRadius:"20px", fontSize:"11px", fontWeight:"700", background:"rgba(45,212,191,0.1)", color:"#2dd4bf", border:"1px solid rgba(45,212,191,0.25)", textTransform:"capitalize" },
    btns: { display:"flex", gap:"8px", marginTop:"10px" },
    photoBtn: { padding:"6px 14px", borderRadius:"7px", border:"1px solid rgba(45,212,191,0.3)", background:"rgba(45,212,191,0.05)", color:"#2dd4bf", fontSize:"11px", fontWeight:"600", cursor:"pointer" },
    removeBtn: { padding:"6px 14px", borderRadius:"7px", border:"1px solid rgba(248,113,113,0.3)", background:"rgba(248,113,113,0.05)", color:"#f87171", fontSize:"11px", fontWeight:"600", cursor:"pointer" },
    grid2: { display:"grid", gridTemplateColumns:"1fr 1fr", gap:"16px", marginBottom:"16px" },
    fieldLabel: { fontSize:"11px", fontWeight:"600", color:"#64748b", display:"block", marginBottom:"5px", textTransform:"uppercase", letterSpacing:"0.8px" },
    input: { width:"100%", padding:"10px 12px", background:"#0f172a", border:"1px solid #334155", borderRadius:"8px", color:"#f1f5f9", fontSize:"13px", outline:"none", boxSizing:"border-box", transition:"border 0.2s" },
    inputDisabled: { width:"100%", padding:"10px 12px", background:"#0a0f1a", border:"1px solid #1e293b", borderRadius:"8px", color:"#475569", fontSize:"13px", boxSizing:"border-box" },
    textarea: { width:"100%", padding:"10px 12px", background:"#0f172a", border:"1px solid #334155", borderRadius:"8px", color:"#f1f5f9", fontSize:"13px", outline:"none", boxSizing:"border-box", resize:"none", lineHeight:1.5 },
    saveBtn: { padding:"10px 24px", borderRadius:"9px", border:"none", background:"linear-gradient(135deg,#0d9488,#0891b2)", color:"white", fontSize:"13px", fontWeight:"700", cursor:"pointer", marginTop:"4px" },
    success: { background:"rgba(74,222,128,0.1)", border:"1px solid rgba(74,222,128,0.3)", color:"#4ade80", padding:"10px 16px", borderRadius:"8px", fontSize:"13px", marginBottom:"16px" },
  };

  return (
    <div style={S.page}>
      <h1 style={S.title}>My Profile</h1>
      <p style={S.sub}>Manage your account information</p>

      {success && <div style={S.success}>âś… {success}</div>}

      <div style={S.card}>
        {/* PHOTO ROW */}
        <div style={S.photoRow}>
          {photo
            ? <img src={photo} alt="Profile" style={S.avatar} />
            : <div style={S.avatarPlaceholder}>{profile.name?.charAt(0)?.toUpperCase()||"?"}</div>
          }
          <div>
            <p style={S.name}>{profile.name}</p>
            <p style={S.email}>{profile.email}</p>
            <span style={S.roleBadge}>{profile.role}</span>
            <div style={S.btns}>
              <button style={S.photoBtn} onClick={()=>fileRef.current.click()}>đź“· Change Photo</button>
              {photo && <button style={S.removeBtn} onClick={()=>{setPhoto(null);localStorage.removeItem("profile_photo");}}>đź—‘ Remove</button>}
            </div>
            <p style={{fontSize:"10px",color:"#475569",marginTop:"4px"}}>JPG, PNG â€” Max 2MB</p>
          </div>
          <input type="file" ref={fileRef} onChange={handlePhoto} accept="image/jpeg,image/png,image/webp" style={{display:"none"}} />
        </div>

        {/* FORM */}
        <div style={S.grid2}>
          <div>
            <label style={S.fieldLabel}>Full Name</label>
            <input name="name" value={profile.name} onChange={handleChange} style={S.input} />
          </div>
          <div>
            <label style={S.fieldLabel}>Phone</label>
            <input name="phone" value={profile.phone} onChange={handleChange} placeholder="+91 98765 43210" style={S.input} />
          </div>
          <div>
            <label style={S.fieldLabel}>Email</label>
            <input value={profile.email} disabled style={S.inputDisabled} />
          </div>
          <div>
            <label style={S.fieldLabel}>Role</label>
            <input value={profile.role} disabled style={{...S.inputDisabled,textTransform:"capitalize"}} />
          </div>
        </div>

        <div style={{marginBottom:"16px"}}>
          <label style={S.fieldLabel}>Skills <span style={{color:"#334155",fontWeight:"400",textTransform:"none"}}>(comma separated)</span></label>
          <input name="skills" value={profile.skills} onChange={handleChange} placeholder="React, Node.js, MySQL..." style={S.input} />
        </div>

        <div style={{marginBottom:"20px"}}>
          <label style={S.fieldLabel}>Bio</label>
          <textarea name="bio" value={profile.bio} onChange={handleChange} rows={3} placeholder="Tell clients about yourself..." style={S.textarea} />
        </div>

        <button onClick={save} disabled={saving} style={{...S.saveBtn,opacity:saving?.7:1}}>
          {saving?"Saving...":"Save Profile"}
        </button>
      </div>
    </div>
  );
}
